define("paygw_pnb/gateways_modal",["paygw_pnb/repository"],(function(Repository){const submitRedirectForm=formdata=>{const form=document.createElement("form");form.method=formdata.method||"post",form.action=formdata.gatewayurl,form.style.display="none",formdata.fields.forEach((field=>{const input=document.createElement("input");input.type="hidden",input.name=field.name,input.value=field.value,form.appendChild(input)})),document.body.appendChild(form),form.submit()},process=(component,paymentArea,itemId,description)=>Repository.getRedirectForm(component,paymentArea,itemId,description).then((formdata=>(submitRedirectForm(formdata),new Promise((()=>{})))));return{process:process}}));
